import AbstractLoader from "@enhavo/form/Loader/AbstractLoader";
import FormRegistry from "@enhavo/app/Form/FormRegistry";
import MaskedType from "@enhavo/form/Type/MaskedType";

export default class MaskedLoader extends AbstractLoader
{
    public insert(element: HTMLElement): void
    {
        let elements = this.findElements(element, '[data-inputmask]');
        for(element of elements) {
            FormRegistry.registerType(new MaskedType(element));
        }
    }
}
